values
('additional-maths:4-2-constraints-and-objective-functions:match:4a8987e5', 'additional-maths', 'additional-maths:4-2-constraints-and-objective-functions', '4.2 Constraints and Objective Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Objective function”?", "options": ["\\( x + y \\)", "\\( x \\ge 2y \\)", "\"Let \\( x = \\) number of ...\"", "The quantity to be maximised or minimised"]}'::jsonb, '{"answer": 3, "explain": "“Objective function” means: The quantity to be maximised or minimised"}'::jsonb),
('additional-maths:4-2-constraints-and-objective-functions:match:c94d2740', 'additional-maths', 'additional-maths:4-2-constraints-and-objective-functions', '4.2 Constraints and Objective Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Constraint”?", "options": ["\\( x \\ge 0,\\ y \\ge 0 \\)", "A limit written as a linear inequality", "right-hand side is \\( 1000 \\)", "\\( x \\ge 2y \\)"]}'::jsonb, '{"answer": 1, "explain": "“Constraint” means: A limit written as a linear inequality"}'::jsonb),
('additional-maths:4-2-constraints-and-objective-functions:match:4c9f9958', 'additional-maths', 'additional-maths:4-2-constraints-and-objective-functions', '4.2 Constraints and Objective Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Total number of items produced”?", "options": ["\\( y \\ge 3 \\)", "\\( 200x + 300y \\le 4200 \\)", "\\( x + y \\)", "\\( \\ge \\)"]}'::jsonb, '{"answer": 2, "explain": "“Total number of items produced” means: \\( x + y \\)"}'::jsonb),
('additional-maths:4-2-constraints-and-objective-functions:match:a90cc7c2', 'additional-maths', 'additional-maths:4-2-constraints-and-objective-functions', '4.2 Constraints and Objective Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Define the variables (first step)”?", "options": ["\\( P = 8x + 12y \\)", "\\( \\ge \\)", "\"Let \\( x = \\) number of ...\"", "The quantity to be maximised or minimised"]}'::jsonb, '{"answer": 2, "explain": "“Define the variables (first step)” means: \"Let \\( x = \\) number of ...\""}'::jsonb),
('additional-maths:4-2-constraints-and-objective-functions:match:c9158965', 'additional-maths', 'additional-maths:4-2-constraints-and-objective-functions', '4.2 Constraints and Objective Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “At least twice as many roses \\( x \\) as lilies \\( y \\)”?", "options": ["The quantity to be maximised or minimised", "\\( x \\ge 2y \\)", "\\( 200x + 300y \\le 4200 \\)", "\\( x \\ge 0,\\ y \\ge 0 \\)"]}'::jsonb, '{"answer": 1, "explain": "“At least twice as many roses \\( x \\) as lilies \\( y \\)” means: \\( x \\ge 2y \\)"}'::jsonb),
('additional-maths:4-2-constraints-and-objective-functions:match:f46f8468', 'additional-maths', 'additional-maths:4-2-constraints-and-objective-functions', '4.2 Constraints and Objective Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Toymaker: £28 per train, £60 per plane, maximise”?", "options": ["\\( P = 28x + 60y \\)", "\\( x \\ge 2y \\)", "A limit written as a linear inequality", "\\( P = 8x + 12y \\)"]}'::jsonb, '{"answer": 0, "explain": "“Toymaker: £28 per train, £60 per plane, maximise” means: \\( P = 28x + 60y \\)"}'::jsonb),
('additional-maths:4-2-constraints-and-objective-functions:match:3dd9c0c2', 'additional-maths', 'additional-maths:4-2-constraints-and-objective-functions', '4.2 Constraints and Objective Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Simplify \\( 6x + 4y \\le 240 \\)”?", "options": ["\\( x + y \\)", "\\( 3x + 2y \\le 120 \\)", "\\( x \\ge 0,\\ y \\ge 0 \\)", "\"Let \\( x = \\) number of ...\""]}'::jsonb, '{"answer": 1, "explain": "“Simplify \\( 6x + 4y \\le 240 \\)” means: \\( 3x + 2y \\le 120 \\)"}'::jsonb),
('additional-maths:4-2-constraints-and-objective-functions:match:7458610f', 'additional-maths', 'additional-maths:4-2-constraints-and-objective-functions', '4.2 Constraints and Objective Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “1 kg of plastic available (grams used)”?", "options": ["\\( y \\ge 3 \\)", "right-hand side is \\( 1000 \\)", "\\( \\ge \\)", "\\( P = 8x + 12y \\)"]}'::jsonb, '{"answer": 1, "explain": "“1 kg of plastic available (grams used)” means: right-hand side is \\( 1000 \\)"}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:8eabb91c', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "The optimum of a linear objective over a feasible region is always found:", "options": ["At a vertex (corner) of the region", "At an interior point of the region", "At the centre of the region", "Halfway along one edge"]}'::jsonb, '{"answer": 0, "explain": "A linear objective reaches its extreme value at a corner of the feasible region, so only the vertices need testing."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:5bab11fa', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "A feasible region has vertices \\( (0,0),\\ (8,0),\\ (4,4),\\ (0,6) \\). Which maximises \\( P = 3x + 4y \\)?", "options": ["\\( (4,4) \\)", "\\( (8,0) \\)", "\\( (0,6) \\)", "\\( (0,0) \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( P \\) is 0, 24, 28, 24 at the four vertices; the maximum 28 is at \\( (4,4) \\)."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:2c5a090c', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "Using OCR''s shading convention, the feasible region is:", "options": ["The region left unshaded", "The region you shade", "The whole grid", "Always the smallest triangle"]}'::jsonb, '{"answer": 0, "explain": "OCR asks you to shade the region that does NOT satisfy the constraints; the feasible region is left clear."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:3649bbb4', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "Minimise \\( C = x + y \\) over a region with vertices \\( (2.5,0),\\ (1,3),\\ (4.75,0) \\). The minimum is at:", "options": ["\\( (2.5,\\ 0) \\), \\( C = 2.5 \\)", "\\( (3,\\ 0) \\), \\( C = 3 \\)", "\\( (1,\\ 3) \\), \\( C = 4 \\)", "an interior point \\( (2,\\ 1.5) \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( C \\) is 2.5, 4 and 4.75 at the three vertices; the minimum 2.5 is at \\( (2.5,0) \\). Choosing \\( (3,0) \\) is the integer-assumption error."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:364f4000', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "To maximise using the objective-line method, you slide the line of constant objective until:", "options": ["It last touches the feasible region at a vertex", "It first enters the region", "It passes through the origin", "It is vertical"]}'::jsonb, '{"answer": 0, "explain": "For a maximum, slide in the direction of increase; the last vertex it touches is the optimum."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:9d3e7e41', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "A student gives the optimum as a point in the middle of the feasible region. The error is:", "options": ["The optimum lies at a vertex, not inside the region", "The point should be on the y-axis", "There is nothing wrong", "The objective must be non-linear"]}'::jsonb, '{"answer": 0, "explain": "A linear objective is optimised at a corner; an interior point is never optimal."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:279e6df5', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "The true minimum of \\( x + y \\) is at \\( (2.5,\\ 0) \\), but a student writes \\( (3,\\ 0) \\). Why is that wrong?", "options": ["They assumed the answer had to be a whole number", "\\( (3,0) \\) is outside the feasible region", "\\( (2.5,0) \\) is not a vertex", "\\( x + y \\) is not linear"]}'::jsonb, '{"answer": 0, "explain": "Optima need not be integers; assuming they must be gives \\( (3,0) \\) with the larger total 3, not the minimum 2.5."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:91582dbb', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "The boundary line \\( 2x + y = 5 \\) cuts the axes at:", "options": ["\\( (0,\\ 5) \\) and \\( (2.5,\\ 0) \\)", "\\( (0,\\ 2.5) \\) and \\( (5,\\ 0) \\)", "\\( (0,\\ 5) \\) and \\( (5,\\ 0) \\)", "\\( (0,\\ 2) \\) and \\( (5,\\ 0) \\)"]}'::jsonb, '{"answer": 0, "explain": "Put \\( x=0 \\Rightarrow y=5 \\); put \\( y=0 \\Rightarrow x=2.5 \\). So the intercepts are \\( (0,5) \\) and \\( (2.5,0) \\)."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:4e896bf8', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "For \\( x + y \\ge 10 \\), using shade-the-NOT convention, which side do you shade?", "options": ["The side where \\( x + y < 10 \\) (below the line)", "The side where \\( x + y > 10 \\) (above the line)", "The boundary line only", "Neither side"]}'::jsonb, '{"answer": 0, "explain": "The unwanted side is where the inequality fails, i.e. \\( x + y < 10 \\), so you shade below the line."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:eac62b26', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "The context needs whole units and the optimum vertex is \\( (2.5,\\ 3.5) \\). You should:", "options": ["Test feasible integer points near \\( (2.5,3.5) \\) and pick the best", "Give \\( (2.5,\\ 3.5) \\) as the answer", "Always round both up to \\( (3,\\ 4) \\)", "Give the origin instead"]}'::jsonb, '{"answer": 0, "explain": "Rounding can leave the region, so check the nearest feasible integer points and choose the one with the best objective."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:95c492d4', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "Which of these is NOT a step in solving an LP problem graphically?", "options": ["Differentiate the objective function", "Formulate the constraints as inequalities", "Shade the unwanted region", "Test the vertices in the objective"]}'::jsonb, '{"answer": 0, "explain": "LP is solved graphically by formulating, shading and testing vertices; differentiation belongs to calculus, not LP."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:mcq:ec2e0aad', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'mcq', 'mcq', 1, '{"question": "Maximising \\( P = 5x + 2y \\), a student picks \\( (0,10) \\) (where \\( P = 20 \\)) over \\( (6,3) \\) (where \\( P = 36 \\)) because \\( y \\) is larger there. The error is:", "options": ["They compared \\( y \\) instead of the objective value \\( P \\)", "\\( (6,3) \\) is not a vertex", "\\( (0,10) \\) is infeasible", "\\( P \\) is not linear"]}'::jsonb, '{"answer": 0, "explain": "You must evaluate the objective \\( P \\) at each vertex; \\( (6,3) \\) gives \\( P = 36 > 20 \\), so it wins."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:tf:e1a2aa1d', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'tf', 'tf', 1, '{"question": "The optimum of a linear objective is always found at a vertex of the feasible region."}'::jsonb, '{"answer": true, "explain": "A linear objective is optimised at a corner of the region, so testing the vertices is enough."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:tf:ebb2a43b', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'tf', 'tf', 1, '{"question": "Using OCR''s convention, you shade the region that satisfies all the constraints."}'::jsonb, '{"answer": false, "explain": "OCR asks you to shade the region that does NOT satisfy the constraints; the feasible region is left clear."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:tf:86d67a14', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'tf', 'tf', 1, '{"question": "The optimal solution to an LP problem must always have whole-number coordinates."}'::jsonb, '{"answer": false, "explain": "Nothing forces integer optima — a real 2024 answer was \\( (2.5,\\ 0) \\). Only a whole-unit context requires integers."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:tf:62a06278', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'tf', 'tf', 1, '{"question": "To maximise by the objective-line method, slide the line as far as possible in the direction of increase until it last touches the feasible region."}'::jsonb, '{"answer": true, "explain": "The last vertex the objective line touches before leaving the region is the maximum."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:tf:4b2423bd', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'tf', 'tf', 1, '{"question": "If the feasible region is empty, the LP problem has no solution."}'::jsonb, '{"answer": true, "explain": "With no point satisfying every constraint, there is nothing to optimise — the problem is infeasible."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:tf:af654c43', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'tf', 'tf', 1, '{"question": "The boundary line \\( 4x + 5y = 19 \\) passes through \\( (0,\\ 3.8) \\) and \\( (4.75,\\ 0) \\)."}'::jsonb, '{"answer": true, "explain": "\\( x=0 \\Rightarrow y = 19/5 = 3.8 \\); \\( y=0 \\Rightarrow x = 19/4 = 4.75 \\)."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:tf:811cfcb3', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'tf', 'tf', 1, '{"question": "When a problem''s context requires whole items, you should check feasible integer points near the optimum vertex."}'::jsonb, '{"answer": true, "explain": "The rounded vertex can fall outside the region, so test the nearest feasible lattice points and pick the best."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:tf:c4a8640a', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'tf', 'tf', 1, '{"question": "A point inside the feasible region can give a better objective value than every vertex."}'::jsonb, '{"answer": false, "explain": "For a linear objective, an interior point never beats the best corner — the optimum is always at a vertex."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:learn:50d4ea39', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'learn', 'mcq', 1, '{"readingTitle": "How do you solve a linear programming problem graphically?", "reading": "<p><strong>Linear programming (LP)</strong> is about squeezing the best possible value out of a situation that is boxed in by rules. Every graphical LP question follows the same three-step shape:</p>\n            <ul>\n              <li><strong>Formulate</strong> — turn the words into <strong>constraints</strong> (linear inequalities) and an <strong>objective function</strong> (the quantity you must maximise or minimise, e.g. \\( P = 3x + 4y \\)). This is lessons 4.1 and 4.2; here you use the result.</li>\n              <li><strong>Shade</strong> — draw each boundary line and shade to leave the <strong>feasible region</strong>: the set of points satisfying <em>every</em> constraint at once.</li>\n              <li><strong>Optimise</strong> — find the point of the feasible region that gives the best objective value, either by <strong>testing every vertex</strong> or by <strong>sliding the objective line</strong>, then read off the optimum and evaluate the objective.</li>\n            </ul>\n            <p>The single most important fact in all of LP: the optimum of a linear objective is <strong>always at a vertex (corner)</strong> of the feasible region — never in the middle. That is what makes the graph so powerful; you only ever have to check the corners.</p>", "question": "In graphical LP, where does the optimum of a linear objective always occur?", "options": ["At a vertex (corner) of the feasible region", "At the centre of the feasible region", "At the origin", "At any point inside the region"]}'::jsonb, '{"answer": 0, "explain": "A linear objective is optimised at a corner of the feasible region — so you only need to test the vertices."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:learn:5c6980ca', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'learn', 'mcq', 1, '{"readingTitle": "How do you shade the feasible region the OCR way?", "reading": "<p>OCR uses one house convention every year, and it catches students out: you <strong>shade the region that does NOT satisfy</strong> the constraints, so the <strong>feasible region is the part left CLEAR (unshaded)</strong>. (This is the opposite of what many textbooks do.)</p>\n            <ul>\n              <li>Draw each boundary line by its <strong>two intercepts</strong> — e.g. \\( 2x + y = 5 \\) runs from \\( (0,\\ 5) \\) to \\( (2.5,\\ 0) \\). A line drawn accurately through its intercepts earns its mark.</li>\n              <li>Solid or dotted lines are both accepted in this qualification, so do not lose sleep over strict/non-strict inequalities on the graph.</li>\n              <li>For each inequality, shade the side the points do <strong>not</strong> want. For \\( 2x + y \\ge 5 \\) (an \"at least\" rule) the unwanted side is where \\( 2x + y < 5 \\) — below the line — so you shade there.</li>\n              <li>Test a point (the origin \\( (0,0) \\) is easiest, if it is not on a line) to decide which side is which: substitute it into the inequality and see whether it is satisfied.</li>\n            </ul>\n            <p>When all the shading is done, the one clear polygon that remains is your feasible region — every candidate optimum is one of its corners.</p>", "question": "Using OCR''s convention, after shading, the feasible region is:", "options": ["The region left unshaded (clear)", "The region you shaded", "Always a triangle", "The largest shaded region"]}'::jsonb, '{"answer": 0, "explain": "OCR asks you to shade the region that does NOT satisfy the constraints, so the feasible region is left clear."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:learn:134afac3', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'learn', 'mcq', 1, '{"readingTitle": "How do you find the optimum by testing the vertices?", "reading": "<p>Because the optimum sits at a corner, the <strong>vertex method</strong> is simple: find the coordinates of every vertex of the feasible region, substitute each into the objective, and pick the best value.</p>\n            <p><strong>Worked example.</strong> A baker makes \\( x \\) fruit loaves and \\( y \\) plain loaves. Oven time gives \\( x + y \\le 8 \\); flour gives \\( x + 2y \\le 12 \\); and \\( x,\\ y \\ge 0 \\). Profit is \\( P = 3x + 4y \\). Maximise \\( P \\).</p>\n            <p>The feasible region has four vertices. To find where the two sloping lines meet, solve \\( x + y = 8 \\) and \\( x + 2y = 12 \\) simultaneously: subtracting gives \\( y = 4 \\), so \\( x = 4 \\) — the vertex \\( (4,\\ 4) \\).</p>\n            <table class=\"worked\">\n              <tr><td><strong>Vertex</strong></td><td><strong>\\( P = 3x + 4y \\)</strong></td></tr>\n              <tr><td>\\( (0,\\ 0) \\)</td><td>\\( 0 \\)</td></tr>\n              <tr><td>\\( (8,\\ 0) \\)</td><td>\\( 24 \\)</td></tr>\n              <tr><td>\\( (4,\\ 4) \\)</td><td>\\( 28 \\) ← maximum</td></tr>\n              <tr><td>\\( (0,\\ 6) \\)</td><td>\\( 24 \\)</td></tr>\n            </table>\n            <svg viewBox=\"0 0 360 280\" width=\"100%\" style=\"max-width:380px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Feasible region with vertices (0,0), (8,0), (4,4) and (0,6); the objective P = 3x + 4y takes its largest value 28 at the vertex (4,4)\"><line x1=\"45\" y1=\"235\" x2=\"340\" y2=\"235\" stroke=\"currentColor\" stroke-width=\"1.3\"/><line x1=\"45\" y1=\"235\" x2=\"45\" y2=\"25\" stroke=\"currentColor\" stroke-width=\"1.3\"/><polygon points=\"340,235 331,231 331,239\" fill=\"currentColor\"/><polygon points=\"45,25 41,34 49,34\" fill=\"currentColor\"/><polygon points=\"45,235 298.3,235 171.7,117.9 45,59.3\" fill=\"currentColor\" fill-opacity=\"0.12\" stroke=\"currentColor\" stroke-width=\"1.6\"/><circle cx=\"45\" cy=\"235\" r=\"3.5\" fill=\"currentColor\"/><circle cx=\"298.3\" cy=\"235\" r=\"3.5\" fill=\"currentColor\"/><circle cx=\"171.7\" cy=\"117.9\" r=\"4.8\" fill=\"currentColor\"/><circle cx=\"45\" cy=\"59.3\" r=\"3.5\" fill=\"currentColor\"/><g font-size=\"11\" fill=\"currentColor\"><text x=\"52\" y=\"250\">(0,0)</text><text x=\"255\" y=\"250\">(8,0)</text><text x=\"176\" y=\"112\">(4,4) max</text><text x=\"8\" y=\"55\">(0,6)</text><text x=\"200\" y=\"205\">feasible region</text><text x=\"332\" y=\"251\">x</text><text x=\"30\" y=\"30\">y</text></g></svg>\n            <p>The maximum profit is \\( £28 \\), made at \\( (4,\\ 4) \\): 4 fruit loaves and 4 plain loaves.</p>", "question": "For the region above, which vertex maximises \\( P = 3x + 4y \\)?", "options": ["\\( (4,\\ 4) \\), giving \\( P = 28 \\)", "\\( (8,\\ 0) \\), giving \\( P = 24 \\)", "\\( (0,\\ 6) \\), giving \\( P = 24 \\)", "The centre of the region"]}'::jsonb, '{"answer": 0, "explain": "Testing each vertex, \\( (4,4) \\) gives \\( P = 28 \\), which beats the 24 at \\( (8,0) \\) and \\( (0,6) \\)."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:learn:eff11b90', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'learn', 'mcq', 1, '{"readingTitle": "How do you find the optimum by sliding the objective line?", "reading": "<p>The second method draws a <strong>line of constant objective</strong> — the \"objective line\". For \\( P = 3x + 4y \\), the line \\( 3x + 4y = k \\) is a family of parallel lines, one for each value of \\( k \\). Bigger \\( k \\) means a line further out.</p>\n            <ul>\n              <li>Draw one objective line for a convenient value (say \\( k = 12 \\)), then imagine sliding it <strong>parallel</strong> to itself.</li>\n              <li>To <strong>maximise</strong>, slide it in the direction of increase until it is about to leave the region — the <strong>last point of contact</strong> is the optimum vertex.</li>\n              <li>To <strong>minimise</strong>, slide it the opposite way until the <strong>first point of contact</strong>.</li>\n            </ul>\n            <p>For the baker, sliding \\( 3x + 4y = k \\) up and to the right, the last corner it touches is \\( (4,\\ 4) \\) — the same answer the vertex method gave. The objective-line method is quickest when a region has many vertices, because you do not have to evaluate them all.</p>\n            <svg viewBox=\"0 0 360 280\" width=\"100%\" style=\"max-width:380px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"The objective line 3x + 4y = k slides up and to the right; its last contact with the feasible region is the vertex (4,4), where the maximum is 28\"><line x1=\"45\" y1=\"235\" x2=\"340\" y2=\"235\" stroke=\"currentColor\" stroke-width=\"1.3\"/><line x1=\"45\" y1=\"235\" x2=\"45\" y2=\"25\" stroke=\"currentColor\" stroke-width=\"1.3\"/><polygon points=\"340,235 331,231 331,239\" fill=\"currentColor\"/><polygon points=\"45,25 41,34 49,34\" fill=\"currentColor\"/><polygon points=\"45,235 298.3,235 171.7,117.9 45,59.3\" fill=\"currentColor\" fill-opacity=\"0.12\" stroke=\"currentColor\" stroke-width=\"1.4\"/><line x1=\"45\" y1=\"176.4\" x2=\"129.5\" y2=\"235\" stroke=\"currentColor\" stroke-width=\"1.2\" stroke-dasharray=\"5 4\" stroke-opacity=\"0.5\"/><line x1=\"45\" y1=\"117.9\" x2=\"213.9\" y2=\"235\" stroke=\"currentColor\" stroke-width=\"1.2\" stroke-dasharray=\"5 4\" stroke-opacity=\"0.7\"/><line x1=\"45\" y1=\"30\" x2=\"298.3\" y2=\"205.7\" stroke=\"currentColor\" stroke-width=\"1.9\" stroke-dasharray=\"6 4\"/><line x1=\"150\" y1=\"184\" x2=\"169\" y2=\"124\" stroke=\"currentColor\" stroke-width=\"1.5\"/><polygon points=\"171.7,117.9 164,127 175,130\" fill=\"currentColor\"/><circle cx=\"171.7\" cy=\"117.9\" r=\"4.8\" fill=\"currentColor\"/><g font-size=\"11\" fill=\"currentColor\"><text x=\"177\" y=\"114\">(4,4) max</text><text x=\"243\" y=\"196\">3x+4y=k</text><text x=\"112\" y=\"180\">slide</text><text x=\"332\" y=\"251\">x</text><text x=\"30\" y=\"30\">y</text></g></svg>", "question": "To MAXIMISE with the objective-line method you slide the line until:", "options": ["Its last point of contact with the feasible region", "It reaches the origin", "It becomes vertical", "It leaves the grid entirely"]}'::jsonb, '{"answer": 0, "explain": "Slide the objective line in the direction of increase; the last vertex it touches before leaving the region is the maximum."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:learn:a2d3779c', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'learn', 'mcq', 1, '{"readingTitle": "Why can the optimum be a decimal — and when must it be a whole number?", "reading": "<p>This is where the marks are won and lost. Nothing in linear programming forces the optimum to have whole-number coordinates. The corner where the objective is best might sit at \\( x = 2.5 \\), and if it does, \\( 2.5 \\) <strong>is</strong> the answer.</p>\n            <ul>\n              <li>In a real 2024 exam, the minimum of \\( x + y \\) was at \\( (2.5,\\ 0) \\). A very common wrong answer was \\( (3,\\ 0) \\) — candidates <strong>assumed</strong> the answer had to be an integer, and lost the marks.</li>\n              <li>So: find the vertex first, exactly. Do <strong>not</strong> round on the way.</li>\n              <li><strong>But</strong> if the context can only take whole units (whole toys, whole tins), the true answer must be a lattice point. Then find the optimum vertex, and test the <strong>integer points nearest to it that are still feasible</strong>, choosing the best. Never just round the vertex — the rounded point can fall outside the region.</li>\n            </ul>\n            <p>Read the context: quantities of a liquid drug in mg can be \\( 2.5 \\); numbers of toys cannot be \\( 4.3 \\). Match the answer to what the situation allows.</p>", "question": "A drug problem''s optimum vertex is at \\( x = 2.5 \\) mg. What should you write?", "options": ["\\( x = 2.5 \\) — it need not be a whole number", "\\( x = 3 \\), rounding up", "\\( x = 2 \\), rounding down", "There is no valid answer"]}'::jsonb, '{"answer": 0, "explain": "Mass in mg can be non-integer, so \\( 2.5 \\) is the correct optimum; rounding to 3 was the common exam error."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:learn:4664db1c', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'learn', 'mcq', 1, '{"readingTitle": "Can you run a whole LP problem from start to finish?", "reading": "<p>Here is the full <strong>formulate → shade → optimise</strong> ladder on one small problem.</p>\n            <p><strong>Problem.</strong> A café makes \\( x \\) fruit smoothies and \\( y \\) protein shakes. Fruit is limited: \\( 2x + y \\le 10 \\). Cups are limited: \\( x + y \\le 7 \\). Also \\( x,\\ y \\ge 0 \\). Each smoothie earns \\( £2 \\) and each shake \\( £3 \\); maximise \\( P = 2x + 3y \\).</p>\n            <table class=\"worked\">\n              <tr><td>1. <strong>Formulate:</strong> constraints \\( 2x + y \\le 10 \\), \\( x + y \\le 7 \\), \\( x,y \\ge 0 \\); objective \\( P = 2x + 3y \\).</td></tr>\n              <tr><td>2. <strong>Boundary lines:</strong> \\( 2x + y = 10 \\) from \\( (0,10) \\) to \\( (5,0) \\); \\( x + y = 7 \\) from \\( (0,7) \\) to \\( (7,0) \\).</td></tr>\n              <tr><td>3. <strong>Shade</strong> the unwanted side of each (the far side from the origin, since \\( (0,0) \\) satisfies both), leaving the feasible region clear.</td></tr>\n              <tr><td>4. <strong>Vertices:</strong> \\( (0,0),\\ (5,0),\\ (0,7) \\), and where the lines cross: solve \\( 2x + y = 10 \\), \\( x + y = 7 \\) → subtract → \\( x = 3 \\), \\( y = 4 \\), i.e. \\( (3,\\ 4) \\).</td></tr>\n              <tr><td>5. <strong>Optimise:</strong> \\( P \\) at \\( (0,0)=0 \\), \\( (5,0)=10 \\), \\( (3,4)=18 \\), \\( (0,7)=21 \\).</td></tr>\n            </table>\n            <p>The maximum is \\( P = £21 \\) at \\( (0,\\ 7) \\): make 0 smoothies and 7 shakes. Whole cups are fine here, and the optimum already lands on integers — but you still checked every corner rather than guessing.</p>", "question": "In the café problem, which corner gives the maximum \\( P = 2x + 3y \\)?", "options": ["\\( (0,\\ 7) \\), giving \\( P = 21 \\)", "\\( (3,\\ 4) \\), giving \\( P = 18 \\)", "\\( (5,\\ 0) \\), giving \\( P = 10 \\)", "\\( (0,\\ 0) \\), giving \\( P = 0 \\)"]}'::jsonb, '{"answer": 0, "explain": "Testing the four vertices, \\( (0,7) \\) gives the largest \\( P = 21 \\)."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:misc:dccaafcc', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The optimum must be a whole number, so \\( (3,\\ 0) \\) is the answer.</p><p><strong>✅ The correct idea:</strong> Optima need not be integers. A weak answer assumes whole numbers and gives \\( (3,0) \\); a strong answer finds the vertex exactly — here the minimum of \\( x+y \\) is at \\( (2.5,\\ 0) \\), value \\( 2.5 \\) — and only rounds if the CONTEXT demands whole units.</p>", "question": "The minimum of \\( x+y \\) is at \\( (2.5,0) \\). The correct value is:", "options": ["\\( 2.5 \\)", "\\( 3 \\)", "\\( 2 \\)", "no minimum exists"]}'::jsonb, '{"answer": 0, "explain": "The vertex is \\( (2.5,0) \\), so the minimum total is \\( 2.5 \\); assuming an integer gives the wrong 3."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:misc:acfb27b3', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Look inside the feasible region for the best point.</p><p><strong>✅ The correct idea:</strong> A weak answer hunts for a point in the middle of the region; a strong answer knows a linear objective is optimised at a VERTEX and tests only the corners.</p>", "question": "Where should you look for the optimum?", "options": ["At the vertices of the region", "In the middle of the region", "Outside the region", "On the y-axis only"]}'::jsonb, '{"answer": 0, "explain": "The optimum of a linear objective is always at a corner, so test the vertices, not interior points."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:misc:229674c0', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Shade the feasible region so it stands out.</p><p><strong>✅ The correct idea:</strong> OCR''s convention is the OPPOSITE: shade the region that does NOT satisfy the constraints. A weak answer shades the wanted region and loses the shading marks; a strong answer leaves the feasible region clear.</p>", "question": "Under OCR''s convention you shade:", "options": ["The unwanted region (not satisfying the constraints)", "The feasible region", "The whole grid", "Nothing at all"]}'::jsonb, '{"answer": 0, "explain": "Shade the NOT-required region; the feasible region is left unshaded."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:misc:21d5ebf1', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Pick the vertex where \\( y \\) (or \\( x \\)) is biggest.</p><p><strong>✅ The correct idea:</strong> A weak answer compares a single variable; a strong answer substitutes each vertex into the OBJECTIVE and compares the objective values. \\( (6,3) \\) can beat \\( (0,10) \\) even though \\( y \\) is smaller, if \\( P \\) is larger there.</p>", "question": "To choose the optimum vertex you compare:", "options": ["The objective value at each vertex", "The \\( y \\)-coordinate of each vertex", "The \\( x \\)-coordinate of each vertex", "The distance from the origin"]}'::jsonb, '{"answer": 0, "explain": "Only the objective value decides the optimum; a single coordinate can mislead."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:misc:a83cce43', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Draw \\( 2x + y = 5 \\) from \\( (0,\\ 2.5) \\) to \\( (5,\\ 0) \\).</p><p><strong>✅ The correct idea:</strong> The intercepts are swapped. A strong answer sets \\( x=0 \\Rightarrow y=5 \\) and \\( y=0 \\Rightarrow x=2.5 \\), so the line runs from \\( (0,\\ 5) \\) to \\( (2.5,\\ 0) \\) — each correct line earns a mark.</p>", "question": "The line \\( 2x + y = 5 \\) runs between:", "options": ["\\( (0,5) \\) and \\( (2.5,0) \\)", "\\( (0,2.5) \\) and \\( (5,0) \\)", "\\( (0,5) \\) and \\( (5,0) \\)", "\\( (2,0) \\) and \\( (0,5) \\)"]}'::jsonb, '{"answer": 0, "explain": "Setting each variable to 0 gives \\( y=5 \\) and \\( x=2.5 \\)."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:tips:1ed73db1', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'tips', 'mcq', 1, '{"readingTitle": "tip — The formulate → shade → optimise ladder", "reading": "<p><strong>0 marks:</strong> jumping straight to an answer with no lines drawn and no vertices tested.</p><p><strong>Partial:</strong> constraints formulated and lines drawn correctly by their intercepts, but the wrong region shaded or only one vertex checked.</p><p><strong>Full marks:</strong> (1) write each constraint as an inequality; (2) draw every boundary line by its two intercepts and shade the NOT-required side; (3) identify every vertex of the clear region, substitute each into the objective, and state the optimum point AND the objective value.</p>", "question": "The three stages of a graphical LP solution are:", "options": ["Formulate, shade, optimise", "Differentiate, integrate, evaluate", "Guess, check, round", "Plot, reflect, rotate"]}'::jsonb, '{"answer": 0, "explain": "Every LP question follows formulate → shade → optimise."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:tips:3952fa09', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'tips', 'mcq', 1, '{"readingTitle": "explain — Optima need not be whole numbers", "reading": "<p>The biggest examiner-reported LP error: assuming the optimum must be an integer. In 2024 the minimum of \\( x+y \\) was at \\( (2.5,\\ 0) \\); the common wrong answer \\( (3,\\ 0) \\) came from students who thought the answer had to be whole.</p><p><strong>Do this:</strong> find the optimum vertex EXACTLY (solve the boundary lines simultaneously); give its coordinates as they are. Only if the context is discrete (whole toys, tins, people) do you then test the nearest FEASIBLE integer points — never blindly round.</p>", "question": "The optimum vertex is \\( (2.5,\\ 0) \\) for a mass in mg. You write:", "options": ["\\( (2.5,\\ 0) \\) — a mass may be a decimal", "\\( (3,\\ 0) \\), rounding up", "\\( (2,\\ 0) \\), rounding down", "no answer, since it is not whole"]}'::jsonb, '{"answer": 0, "explain": "Mass in mg can be 2.5, so the exact vertex is the answer; rounding to 3 loses the marks."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:tips:55bc0f65', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'tips', 'mcq', 1, '{"readingTitle": "tip — Two routes to the optimum — pick one and show it", "reading": "<p>The mark scheme rewards visible method. Either <strong>list the vertices with their objective values</strong> (and do not cross out the ones you reject — a crossed-out line is treated as withdrawn), or <strong>draw the objective line</strong> on the grid and show it sliding to the optimum corner (\"sight of \\( P = kx + \\dots \\) soi\" earns the method mark). A bare answer with no working can score zero on these.</p>", "question": "Which earns the method mark on an LP optimisation?", "options": ["A list of vertices with their objective values, or the objective line drawn", "The final answer only, with no working", "A decimal to 5 d.p.", "The feasible region shaded twice"]}'::jsonb, '{"answer": 0, "explain": "Show either the vertex-value list or the objective line; the method must be visible."}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:fib:cd91fc7b', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'fib', 'fib', 2, '{"question": "In OCR linear programming you shade the region that does ___B1___ satisfy the constraints, so the feasible region is left ___B2___.", "blankOptions": {"B1": ["constraint", "whole", "3.8", "not"], "B2": ["centre", "integers", "unshaded", "5"]}}'::jsonb, '{"blanks": {"B1": "not", "B2": "unshaded"}}'::jsonb),
('additional-maths:4-3-solving-lp-problems-graphically:fib:6febcbe3', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'fib', 'fib', 1, '{"question": "The optimum value of a linear objective always lies at a ___B1___ of the feasible region, never inside it.", "blankOptions": {"B1": ["edge", "vertex", "whole", "does"]}}'::jsonb, '{"blanks": {"B1": "vertex"}}'::jsonb),
