('additional-maths:4-3-solving-lp-problems-graphically:fib:7dd73b2c', 'additional-maths', 'additional-maths:4-3-solving-lp-problems-graphically', '4.3 Solving LP Problems Graphically', 'fib', 'fib', 2, '{"question": "The boundary line \\( 2x + y = 5 \\) has \\( y \\)-intercept ___B1___ and \\( x \\)-intercept ___B2___.", "blankOptions": {"B1": ["greater", "3.8", "5", "constraint"], "B2": ["objective", "not", "2.5", "3.8"]}}'::jsonb, '{"blanks": {"B1": "5", "B2": "2.5"}}'::jsonb),
